var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양!","JPN":"カリンさん！","ENG":"Karin!","TWN":"卡琳小姐！"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아...... 시영 씨.","JPN":"あ……シノンさん。","ENG":"Ah... Shiyoung.","TWN":"啊……時雨小姐。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"수고했어요...... 이제 다 끝났습니다.","JPN":"お疲れ様でした……これですべておしまいです。","ENG":"Good job... It's over now.","TWN":"辛苦妳了……現在都結束了。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"한 번 차원 통로가 안정화 된 이상 이제 돌이킬 방법은 없습니다.","JPN":"一度次元間通路ができた以上、引き返すことはできません。","ENG":"Now that the dimensional passageway has settled into place, there's no turning back.","TWN":"一旦次元通道被固定，就再也沒有辦法扭轉了。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"곧 이쪽 세상으로 <color=#ffd34c>네피림</color>이 건너올 거에요.","JPN":"もうすぐこちら側に、<color=#ffd34c>ネフィリム</color>がやってくるでしょう。","ENG":"Soon, the <color=#ffd34c>Nephil</color> will come over here.","TWN":"<color=#ffd34c>諾菲力</color>馬上就要到這個世界來了。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨는 어디든 도망가도 괜찮습니다. 임무는 끝났어요.","JPN":"シノンさんはどこかへ逃げてもらって構いません。任務は終了です。","ENG":"Shiyoung, you can run. Your job here is done.","TWN":"時雨小姐逃去其他地方也沒關係。任務已經結束了。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"도망? 카린 양은요?","JPN":"逃げるって？　カリンさんは？","ENG":"I can run? What about you, Karin?","TWN":"逃跑？卡琳小姐呢？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......저는 이곳에 남습니다.","JPN":"……私はここに残ります。","ENG":"I'm staying.","TWN":"……我要留在這裡。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이곳이 아무것도 없는 무저갱이었다면 미련 없이 도망쳤겠지만......","JPN":"ここが何も存在しない不毛の地だったら、構わず逃げたでしょうけど……","ENG":"I would have left this place without regret if it was a wasteland with nothing in it,","TWN":"如果這裡是什麼都沒有的無底洞，我大概會毫不猶豫的逃跑……"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"사람이 살고 있다는 걸 알고 있는 한, 그걸 무시한 채 떠날 순 없어요.","JPN":"人間がいることを知った以上、見て見ぬふりをして離れるわけにはいきません。","ENG":"but now that I know it's inhabited by people, I can't ignore them.","TWN":"不過既然知道這裡有人活著，那就不能無視他們從這裡逃跑了。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"흐음, 가능성 없는 싸움에 목숨을 던지다니.","JPN":"ふーん、勝算のない戦いに命をかけるなんて。","ENG":"Hm, you want to throw your life away over a losing battle.","TWN":"哦，居然要為這種沒有可能性的戰鬥賭上性命。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"제가 알고 있던 당신은 좀 더 계산적이고 현실주의적이었는데 말이죠.","JPN":"私の知るあなたは、もっと論理的で現実主義だったと思いますが。","ENG":"I thought you were more calculating and realistic than that.","TWN":"據我所知，妳應該是更加精明、更加現實主義的人吧。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"군인은 임무를 위해 언제나 냉철함을 유지해야 합니다.","JPN":"軍人は任務のために、常に冷静さを保つ必要があります。","ENG":"We soldiers must remain coolheaded while on our missions.","TWN":"軍人要執行任務必須時刻保持冷靜。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그리고 제게 주어진 임무는......","JPN":"それに、私に与えられた任務は……","ENG":"And my mission this time...","TWN":"而我的任務……"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"방금 전에 성공적으로 완수했어요.","JPN":"ついさっき、無事完遂しました。","ENG":"I successfully accomplished it just now.","TWN":"剛才已經結束了。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......그뿐입니다.","JPN":"……それだけのことです。","ENG":"I have no regrets.","TWN":"……僅此而已。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"고작 한 사람이 두 세상을 지키기 위해 목숨 바친다, 라......","JPN":"たった一人で、二つの世界を守るために命を捧げる、か……","ENG":"You're just one woman, and you're ready to die fighting for two worlds.","TWN":"至少一個人能為守護兩個世界獻出生命，是嗎……"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"저로선 감히 상상도 못할 일이네요.","JPN":"私にはとても想像できませんね。","ENG":"I can't even imagine doing such a thing.","TWN":"我根本無法想像的事情呢。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"혹시 아예 네피림을 쓰러뜨린다는 선택지는 없나요?","JPN":"いっそのこと、ネフィリムを倒すって選択肢はありませんか？","ENG":"Aren't there other options, to bring down the Nephil for example?","TWN":"難道就沒有消滅諾菲力這個選項嗎？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};